import{_ as t,c as n,o as a,a1 as i}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Erweiterte Konfiguration: Detaillierte Funktionen | Antigravity-Manager","description":"Erfahren Sie mehr über die erweiterte Konfiguration von Antigravity-Manager. Beherrschen Sie fortgeschrittene Funktionen wie Kontoverwaltung, Modellrouting, Quotenmanagement und Überwachungsstatistiken.","frontmatter":{"title":"Erweiterte Konfiguration: Detaillierte Funktionen | Antigravity-Manager","order":300,"sidebarTitle":"System auf Produktionsniveau bringen","subtitle":"Erweiterte Konfiguration: Detaillierte Funktionen","description":"Erfahren Sie mehr über die erweiterte Konfiguration von Antigravity-Manager. Beherrschen Sie fortgeschrittene Funktionen wie Kontoverwaltung, Modellrouting, Quotenmanagement und Überwachungsstatistiken."},"headers":[],"relativePath":"de/lbjlaq/Antigravity-Manager/advanced/index.md","filePath":"de/lbjlaq/Antigravity-Manager/advanced/index.md"}'),r={name:"de/lbjlaq/Antigravity-Manager/advanced/index.md"};function o(s,e,l,d,u,h){return a(),n("div",null,[...e[0]||(e[0]=[i(`<h1 id="erweiterte-konfiguration" tabindex="-1">Erweiterte Konfiguration <a class="header-anchor" href="#erweiterte-konfiguration" aria-label="Permalink to &quot;Erweiterte Konfiguration&quot;">​</a></h1><p>Dieses Kapitel vertieft die fortgeschrittenen Funktionen von Antigravity Tools: Konfigurationsmanagement, Sicherheitsstrategien, Kontoverwaltung, Modellrouting, Quotenmanagement, Überwachungsstatistiken sowie Server-Bereitstellungsoptionen. Nachdem Sie diese Inhalte beherrschen, können Sie Antigravity Tools von &quot;funktionierend&quot; auf &quot;benutzerfreundlich, stabil und betriebsbereit&quot; upgraden.</p><h2 id="in-diesem-kapitel" tabindex="-1">In diesem Kapitel <a class="header-anchor" href="#in-diesem-kapitel" aria-label="Permalink to &quot;In diesem Kapitel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tutorial</th><th>Beschreibung</th></tr></thead><tbody><tr><td><a href="./config/">Konfiguration komplett</a></td><td>Vollständige Felder von AppConfig/ProxyConfig, Speicherorte und Hot-Update-Semantik</td></tr><tr><td><a href="./security/">Sicherheit und Datenschutz</a></td><td><code>auth_mode</code>, <code>allow_lan_access</code> und Sicherheitsbaseline-Design</td></tr><tr><td><a href="./scheduling/">Hochverfügbare Verwaltung</a></td><td>Rotation, feste Konten, klebrige Sitzungen und Retry-Mechanismen</td></tr><tr><td>---</td><td>---</td></tr><tr><td><a href="./quota/">Quotenmanagement</a></td><td>Kombinationsstrategie aus Quota Protection + Smart Warmup</td></tr><tr><td><a href="./monitoring/">Proxy Monitor</a></td><td>Anforderungsprotokolle, Filterung, Detailrekonstruktion und Export</td></tr><tr><td><a href="./token-stats/">Token-Statistiken</a></td><td>Kostenperspektive und Diagramminterpretation</td></tr><tr><td>---</td><td>---</td></tr><tr><td><a href="./system/">Systemfunktionen</a></td><td>Mehrsprachigkeit/Themen/Updates/Autostart/HTTP API Server</td></tr><tr><td><a href="./deployment/">Server-Bereitstellung</a></td><td>Docker noVNC vs Headless Xvfb Auswahl und Betrieb</td></tr></tbody></table><h2 id="empfohlener-lernpfad" tabindex="-1">Empfohlener Lernpfad <a class="header-anchor" href="#empfohlener-lernpfad" aria-label="Permalink to &quot;Empfohlener Lernpfad&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Empfohlene Reihenfolge</p><p>Dieses Kapitel enthält umfangreiche Inhalte. Es wird empfohlen, sie in Modulen zu lernen:</p></div><p><strong>Erste Phase: Konfiguration und Sicherheit (Pflicht)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Konfiguration komplett → Sicherheit und Datenschutz</span></span>
<span class="line"><span>config                   security</span></span></code></pre></div><p>Verstehen Sie zunächst das Konfigurationssystem (was einen Neustart erfordert, was Hot-Update unterstützt), dann lernen Sie die Sicherheitseinstellungen (insbesondere bei Exposition im LAN/Internet).</p><p><strong>Zweite Phase: Verwaltung und Routing (Empfohlen)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hochverfügbare Verwaltung → Modell-Routing</span></span>
<span class="line"><span>scheduling               model-router</span></span></code></pre></div><p>Lernen Sie, wie Sie maximale Stabilität mit minimaler Anzahl von Konten erreichen, und nutzen Sie dann Modell-Routing, um Upstream-Änderungen zu abstrahieren.</p><p><strong>Dritte Phase: Quoten und Überwachung (Bei Bedarf)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Quotenmanagement → Proxy Monitor → Token-Statistiken</span></span>
<span class="line"><span>quota            monitoring      token-stats</span></span></code></pre></div><p>Verhindern Sie unbemerkte Quotenverschwendung, machen Sie die Blackbox zu einem beobachtbaren System und quantifizieren Sie die Kostenoptimierung.</p><p><strong>Vierte Phase: Stabilität und Bereitstellung (Fortgeschritten)</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Stabilität langer Sitzungen → Systemfunktionen → Server-Bereitstellung</span></span>
<span class="line"><span>context-compression          system          deployment</span></span></code></pre></div><p>Lösen Sie die versteckten Probleme langer Sitzungen, machen Sie den Client mehr zu einem Produkt, und lernen Sie schließlich die Server-Bereitstellung.</p><p><strong>Schnellauswahl</strong>:</p><table tabindex="0"><thead><tr><th>Ihre Szenario</th><th>Empfohlen zuerst</th></tr></thead><tbody><tr><td>Mehrkontenrotation instabil</td><td><a href="./scheduling/">Hochverfügbare Verwaltung</a></td></tr><tr><td>Einen Modellnamen fixieren</td><td><a href="./model-router/">Modell-Routing</a></td></tr><tr><td>Quoten immer verbraucht</td><td><a href="./quota/">Quotenmanagement</a></td></tr><tr><td>Anforderungsprotokolle ansehen</td><td><a href="./monitoring/">Proxy Monitor</a></td></tr><tr><td>---</td><td>---</td></tr><tr><td>Lange Konversationen fehleranfällig</td><td><a href="./context-compression/">Stabilität langer Sitzungen</a></td></tr><tr><td>Im LAN freigeben</td><td><a href="./security/">Sicherheit und Datenschutz</a></td></tr><tr><td>Auf Server bereitstellen</td><td><a href="./deployment/">Server-Bereitstellung</a></td></tr></tbody></table><h2 id="voraussetzungen" tabindex="-1">Voraussetzungen <a class="header-anchor" href="#voraussetzungen" aria-label="Permalink to &quot;Voraussetzungen&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Bitte vor dem Start bestätigen</p><ul><li><a href="./../start/">Schnellstart</a>-Kapitel abgeschlossen (mindestens Installation, Konto hinzufügen, Reverse-Proxy starten)</li><li>Mindestens ein Protokoll aus <a href="./../platforms/">Plattformen und Integrationen</a> integriert (z.B. OpenAI oder Anthropic)</li><li>Lokaler Reverse-Proxy antwortet korrekt auf Anforderungen</li></ul></div><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Nach Abschluss dieses Kapitels können Sie weiter lernen:</p><ul><li><a href="./../faq/">Häufig gestellte Fragen</a>: Leitfaden zur Fehlerbehebung bei Problemen wie 401/404/429/Streaming-Unterbrechungen</li><li><a href="./../appendix/">Anhang</a>: Referenzmaterial wie Endpunkte-Schnellreferenz, Datenmodelle, Grenzen von z.ai-Funktionen usw.</li></ul>`,25)])])}const c=t(r,[["render",o]]);export{g as __pageData,c as default};
